import 'app_colors.dart';
class AppTheme { AppTheme._(); static ThemeData get light=>ThemeData(useMaterial3:true,brightness:Brightness.light,scaffoldBackgroundColor:Colors.white,colorScheme:ColorScheme.fromSeed(seedColor:AppColors.palm),appBarTheme:const AppBarTheme(centerTitle:false,elevation:0,backgroundColor:Colors.white,foregroundColor:AppColors.ink),cardTheme:CardThemeData(color:AppColors.card,elevation:0,shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(24))),inputDecorationTheme:InputDecorationTheme(filled:true,fillColor:Colors.white,border:OutlineInputBorder(borderRadius:BorderRadius.circular(18),borderSide:BorderSide.none),focusedBorder:OutlineInputBorder(borderRadius:BorderRadius.circular(18),borderSide:const BorderSide(color:AppColors.palm,width:1.5))),elevatedButtonTheme:ElevatedButtonThemeData(style:ElevatedButton.styleFrom(backgroundColor:AppColors.palm,foregroundColor:Colors.white,minimumSize:const Size.fromHeight(54),shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(18))))); static ThemeData get dark=>ThemeData(useMaterial3:true,brightness:Brightness.dark,colorScheme:ColorScheme.fromSeed(seedColor:AppColors.palm,brightness:Brightness.dark)); }
